#!/usr/bin/env python3
"""
Plot a Hofstadter-butterfly CSV (flux, eigenvalue per row) as a
scatter SVG. Reads CSVs generated by Huoma's
`examples/hofstadter_butterfly.rs` Rust example.

Usage:
    .venv/bin/python plot_butterfly.py <csv_in> <svg_out> [title]
"""

from __future__ import annotations

import csv
import sys
from pathlib import Path

import matplotlib

matplotlib.use("Agg")  # no display; SVG only
import matplotlib.pyplot as plt


def main() -> int:
    if len(sys.argv) not in (3, 4):
        print(
            f"usage: {sys.argv[0]} <csv_in> <svg_out> [title]",
            file=sys.stderr,
        )
        return 1
    csv_in = Path(sys.argv[1])
    svg_out = Path(sys.argv[2])
    title = sys.argv[3] if len(sys.argv) == 4 else f"Hofstadter butterfly: {csv_in.stem}"

    fluxes: list[float] = []
    eigvals: list[float] = []
    with csv_in.open() as f:
        reader = csv.reader(f)
        header = next(reader)
        assert header == ["flux", "eigenvalue"], f"unexpected header {header!r}"
        for row in reader:
            fluxes.append(float(row[0]))
            eigvals.append(float(row[1]))

    fig, ax = plt.subplots(figsize=(8, 8), dpi=100)
    ax.scatter(fluxes, eigvals, s=0.6, c="black", marker=".", alpha=0.55, edgecolors="none", rasterized=True)
    ax.set_xlabel(r"flux $\Phi / \Phi_0$ per plaquette")
    ax.set_ylabel(r"energy $E / t$")
    ax.set_title(title)
    ax.set_xlim(min(fluxes), max(fluxes))
    e_pad = 0.05 * (max(eigvals) - min(eigvals))
    ax.set_ylim(min(eigvals) - e_pad, max(eigvals) + e_pad)
    ax.grid(True, alpha=0.2, linewidth=0.5)
    fig.tight_layout()
    fig.savefig(svg_out, format="svg")
    print(f"wrote {svg_out}  ({len(fluxes):,} points)")
    return 0


if __name__ == "__main__":
    sys.exit(main())
